import { HorizontalScrollGallery } from "@/components/ui/horizontal-scroll-gallery";

const images = [
  "https://images.unsplash.com/photo-1618005182384-a83a8bd57fbe?w=600",
  "https://images.unsplash.com/photo-1547658719-da2b51169166?w=600",
  "https://images.unsplash.com/photo-1555066931-4365d14bab8c?w=600",
  "https://images.unsplash.com/photo-1498050108023-c5249f4df085?w=600",
];

export default function PortfolioGallery() {
  return (
    <HorizontalScrollGallery
      items={images.map((src, i) => (
        <img key={i} src={src} alt="Project" className="h-64 w-96 object-cover rounded-2xl" />
      ))}
    />
  );
}

import { HorizontalScrollGallery } from "@/components/ui/horizontal-scroll-gallery";

const features = [
  { title: "Animations", desc: "Spring-driven motion on every component." },
  { title: "CLI", desc: "Install any component in seconds." },
  { title: "Docs", desc: "Live previews with copy-paste code." },
  { title: "Open Source", desc: "MIT licensed, forever free." },
];

export default function FeatureReel() {
  return (
    <HorizontalScrollGallery
      items={features.map((f, i) => (
        <div key={i} className="w-72 h-44 rounded-2xl bg-neutral-900 border border-neutral-800 p-6 flex flex-col justify-between">
          <h3 className="text-white font-bold text-xl">{f.title}</h3>
          <p className="text-neutral-400 text-sm">{f.desc}</p>
        </div>
      ))}
    />
  );
}
